from dataclasses import dataclass, field
from typing import List, Dict, Optional
from collections import defaultdict
import time
import numpy as np

@dataclass
class ExecutionRecord:
    backend: str
    circuit_name: str
    success: bool
    fidelity: float
    depth: int
    cx_count: int
    duration_ms: float
    timestamp: float = field(default_factory=time.time)

class QuantumMetricsRecorder:
    """
    Records and aggregates quantum execution metrics.
    """

    def __init__(self):
        self.records: List[ExecutionRecord] = []
        self._by_backend: Dict[str, List[ExecutionRecord]] = defaultdict(list)
        self._by_circuit: Dict[str, List[ExecutionRecord]] = defaultdict(list)

    def record_execution(self, record: ExecutionRecord):
        """
        Record a single execution.
        """
        self.records.append(record)
        self._by_backend[record.backend].append(record)
        self._by_circuit[record.circuit_name].append(record)

    def get_success_rate(self, backend: Optional[str] = None) -> float:
        """
        Get success rate, optionally filtered by backend.
        """
        records = self._by_backend[backend] if backend else self.records
        if not records:
            return 0.0
        successes = sum(1 for r in records if r.success)
        return successes / len(records)

    def get_average_fidelity(self, backend: Optional[str] = None) -> float:
        """
        Get average fidelity of successful executions.
        """
        records = self._by_backend[backend] if backend else self.records
        successful = [r for r in records if r.success]
        if not successful:
            return 0.0
        return sum(r.fidelity for r in successful) / len(successful)

    def get_depth_percentile(self, percentile: float) -> float:
        """
        Get the nth percentile of circuit depths.
        """
        if not self.records:
            return 0.0
        depths = [r.depth for r in self.records]
        return float(np.percentile(depths, percentile))

    def get_metrics_summary(self) -> Dict:
        """
        Get a complete metrics summary.
        """
        if not self.records:
            return {'total_executions': 0}

        return {
            'total_executions': len(self.records),
            'success_rate': self.get_success_rate(),
            'average_fidelity': self.get_average_fidelity(),
            'depth_p50': self.get_depth_percentile(50),
            'depth_p95': self.get_depth_percentile(95),
            'backends': list(self._by_backend.keys()),
            'circuits': list(self._by_circuit.keys()),
            'by_backend': {
                backend: {
                    'count': len(records),
                    'success_rate': self.get_success_rate(backend),
                    'avg_fidelity': self.get_average_fidelity(backend)
                }
                for backend, records in self._by_backend.items()
            }
        }

from typing import Dict, List, Any
import yaml

def generate_quantum_alerts(
    fidelity_threshold: float = 0.8,
    failure_rate_threshold: float = 0.1,
    queue_length_threshold: int = 50,
    calibration_age_threshold_hours: int = 24
) -> str:
    """
    Generate Prometheus alerting rules for quantum applications.
    """
    rules = {
        'groups': [
            {
                'name': 'quantum_alerts',
                'rules': [
                    {
                        'alert': 'LowFidelity',
                        'expr': f'quantum_fidelity_estimate < {fidelity_threshold}',
                        'for': '5m',
                        'labels': {
                            'severity': 'warning'
                        },
                        'annotations': {
                            'summary': 'Low fidelity detected on {{ $labels.backend }}',
                            'description': f'Fidelity on {{{{ $labels.backend }}}} dropped below {fidelity_threshold}. Current value: {{{{ $value | printf "%.2f" }}}}'
                        }
                    },
                    {
                        'alert': 'HighFailureRate',
                        'expr': f'sum(rate(quantum_circuit_executions_total{{status="failure"}}[5m])) by (backend) / sum(rate(quantum_circuit_executions_total[5m])) by (backend) > {failure_rate_threshold}',
                        'for': '5m',
                        'labels': {
                            'severity': 'critical'
                        },
                        'annotations': {
                            'summary': 'High failure rate on {{ $labels.backend }}',
                            'description': f'Execution failure rate exceeded {failure_rate_threshold*100}%. Current rate: {{{{ $value | printf "%.1f%%" }}}}'
                        }
                    },
                    {
                        'alert': 'LongQueue',
                        'expr': f'quantum_backend_queue_length > {queue_length_threshold}',
                        'for': '15m',
                        'labels': {
                            'severity': 'warning'
                        },
                        'annotations': {
                            'summary': 'Long queue on {{ $labels.backend }}',
                            'description': f'Queue length exceeded {queue_length_threshold} jobs. Current length: {{{{ $value }}}}'
                        }
                    },
                    {
                        'alert': 'StaleCalibration',
                        'expr': f'quantum_calibration_age_hours > {calibration_age_threshold_hours}',
                        'for': '1h',
                        'labels': {
                            'severity': 'warning'
                        },
                        'annotations': {
                            'summary': 'Stale calibration on {{ $labels.backend }}',
                            'description': f'Calibration is older than {calibration_age_threshold_hours} hours. Age: {{{{ $value | printf "%.1f" }}}} hours'
                        }
                    }
                ]
            }
        ]
    }

    return yaml.dump(rules, default_flow_style=False, sort_keys=False)

