from typing import Dict, Any, List

def create_gauge_panel(
    title: str,
    metric: str,
    thresholds: List[Dict[str, Any]],
    unit: str = 'percent'
) -> Dict[str, Any]:
    """
    Create a Grafana gauge panel configuration.
    """
    return {
        'title': title,
        'type': 'gauge',
        'targets': [
            {
                'expr': metric,
                'legendFormat': '{{backend}}'
            }
        ],
        'fieldConfig': {
            'defaults': {
                'unit': unit,
                'thresholds': {
                    'mode': 'absolute',
                    'steps': thresholds
                }
            }
        },
        'options': {
            'showThresholdLabels': False,
            'showThresholdMarkers': True
        }
    }

def create_timeseries_panel(
    title: str,
    metrics: List[str],
    legend_format: str = '{{backend}}'
) -> Dict[str, Any]:
    """
    Create a Grafana timeseries panel configuration.
    """
    return {
        'title': title,
        'type': 'timeseries',
        'targets': [
            {
                'expr': metric,
                'legendFormat': legend_format
            }
            for metric in metrics
        ],
        'fieldConfig': {
            'defaults': {
                'custom': {
                    'drawStyle': 'line',
                    'lineInterpolation': 'smooth',
                    'showPoints': 'auto'
                }
            }
        },
        'options': {
            'legend': {
                'displayMode': 'list',
                'placement': 'bottom'
            }
        }
    }

def create_quantum_dashboard() -> Dict[str, Any]:
    """
    Create a complete quantum monitoring dashboard.
    """
    fidelity_thresholds = [
        {'color': 'red', 'value': 0},
        {'color': 'yellow', 'value': 0.7},
        {'color': 'green', 'value': 0.9}
    ]

    success_thresholds = [
        {'color': 'red', 'value': 0},
        {'color': 'yellow', 'value': 80},
        {'color': 'green', 'value': 95}
    ]

    return {
        'dashboard': {
            'title': 'Quantum Application Monitoring',
            'tags': ['quantum', 'monitoring'],
            'panels': [
                {
                    **create_gauge_panel(
                        'Current Fidelity',
                        'quantum_fidelity_estimate',
                        fidelity_thresholds,
                        'percentunit'
                    ),
                    'gridPos': {'h': 6, 'w': 6, 'x': 0, 'y': 0}
                },
                {
                    **create_gauge_panel(
                        'Success Rate',
                        'sum(rate(quantum_circuit_executions_total{status="success"}[5m])) / sum(rate(quantum_circuit_executions_total[5m])) * 100',
                        success_thresholds,
                        'percent'
                    ),
                    'gridPos': {'h': 6, 'w': 6, 'x': 6, 'y': 0}
                },
                {
                    **create_timeseries_panel(
                        'Fidelity Over Time',
                        ['quantum_fidelity_estimate'],
                        '{{backend}} - {{circuit_name}}'
                    ),
                    'gridPos': {'h': 8, 'w': 12, 'x': 0, 'y': 6}
                },
                {
                    **create_timeseries_panel(
                        'Circuit Depth',
                        ['histogram_quantile(0.95, sum(rate(quantum_circuit_depth_bucket[5m])) by (le, backend))'],
                        'p95 - {{backend}}'
                    ),
                    'gridPos': {'h': 8, 'w': 12, 'x': 12, 'y': 6}
                }
            ]
        }
    }
